import { configureStore, createSlice } from "@reduxjs/toolkit";

const statusSlice = createSlice({
  name: "status",
  initialState: {
    blockObsId: null,
    showBypass: false,
    autoDrivingCars: {},
    vehicleStatus: {},
    adVersion: '',
  },
  reducers: {
    setBlockObsId: (state, action) => {
      state.blockObsId = action.payload;
    },

    toggleBypass: (state) => {
      state.showBypass = !state.showBypass;
    },

    setAutoDrivingCars: (state, action) => {
      state.autoDrivingCars = action.payload;
    },

    setVehicleStatus: (state, action) => {
      state.vehicleStatus = action.payload;
    },

    setAdVersion: (state, action) => {
      state.adVersion = action.payload;
    },
  },
});

export const {
  toggleBypass,
  setBlockObsId,
  setAutoDrivingCars,
  setVehicleStatus,
  setAdVersion,
} = statusSlice.actions;

const store = configureStore({
  reducer: {
    status: statusSlice.reducer,
  },
});

export default store;
