import React, { useEffect, useRef, useState } from "react";
import WebSocketClient from "./utils/websocket";
import { useDispatch, useSelector } from "react-redux";
import {
  toggleBypass,
  setBlockObsId,
  setAutoDrivingCars,
  setVehicleStatus,
  setAdVersion,
} from "./store";
import yards from "./utils/yards";
import trains from "./utils/trains";
import {
  Modal,
  Cascader,
  Form,
  Select,
  Input,
  Button,
  Space,
  Card,
  Flex,
  Popconfirm,
  message,
  Col,
  Row,
  Statistic,
} from "antd";

const worker = new Worker(new URL("./utils/webworker.js", import.meta.url));
const ws = new WebSocketClient();
const tailLayout = {
  wrapperCol: { offset: 8, span: 16 },
};
const typeOptions = [
  { value: "DEFAULT", label: "DEFAULT" },
  { value: "PARKINGSPACE", label: "PARKINGSPACE" },
  { value: "RAILWAY_WAITINGAREA_STATIC", label: "RAILWAY_WAITINGAREA_STATIC" },
  {
    value: "RAILWAY_WAITINGAREA_DYNAMIC",
    label: "RAILWAY_WAITINGAREA_DYNAMIC",
  },
  {
    value: "RAILWAY_OPERATIONAREA_DYNAMIC",
    label: "RAILWAY_OPERATIONAREA_DYNAMIC",
  },
  {
    value: "LOADING_OPERATIONAREA_SAMEDIRECTION_1",
    label: "LOADING_OPERATIONAREA_SAMEDIRECTION_1",
  },
  {
    value: "LOADING_OPERATIONAREA_SAMEDIRECTION_2",
    label: "LOADING_OPERATIONAREA_SAMEDIRECTION_2",
  },
  {
    value: "LOADING_OPERATIONAREA_SAMEDIRECTION_3_0",
    label: "LOADING_OPERATIONAREA_SAMEDIRECTION_3_0",
  },
  {
    value: "LOADING_OPERATIONAREA_SAMEDIRECTION_3_1",
    label: "LOADING_OPERATIONAREA_SAMEDIRECTION_3_1",
  },
  {
    value: "LOADING_OPERATIONAREA_DIFFDIRECTION_1",
    label: "LOADING_OPERATIONAREA_DIFFDIRECTION_1",
  },
  { value: "YARD_WAITINGAREA_STATIC", label: "YARD_WAITINGAREA_STATIC" },
  { value: "YARD_OPERATIONAREA_STATIC", label: "YARD_OPERATIONAREA_STATIC" },
  { value: "YARD_OPERATIONAREA_DYNAMIC", label: "YARD_OPERATIONAREA_DYNAMIC" },
  {
    value: "UNLOAD_OPERATIONAREA_SAMEDIRECTION_1",
    label: "UNLOAD_OPERATIONAREA_SAMEDIRECTION_1",
  },
  {
    value: "UNLOAD_OPERATIONAREA_SAMEDIRECTION_2",
    label: "UNLOAD_OPERATIONAREA_SAMEDIRECTION_2",
  },
  {
    value: "UNLOAD_OPERATIONAREA_SAMEDIRECTION_3_0",
    label: "UNLOAD_OPERATIONAREA_SAMEDIRECTION_3_0",
  },
  {
    value: "UNLOAD_OPERATIONAREA_SAMEDIRECTION_3_1",
    label: "UNLOAD_OPERATIONAREA_SAMEDIRECTION_3_1",
  },
  {
    value: "UNLOAD_OPERATIONAREA_DIFFDIRECTION_1",
    label: "UNLOAD_OPERATIONAREA_DIFFDIRECTION_1",
  },
  {
    value: "BACKWARD_ROUTING_NEED_PLANNING_REROUTING",
    label: "BACKWARD_ROUTING_NEED_PLANNING_REROUTING",
  },
  { value: "BACKWARD_ROUTING_DIRECTLY", label: "BACKWARD_ROUTING_DIRECTLY" },
  { value: "LONG_ADJUSTMENT_FRONT", label: "LONG_ADJUSTMENT_FRONT" },
  { value: "LONG_ADJUSTMENT_BACK", label: "LONG_ADJUSTMENT_BACK" },
];

const yardOptions = yards.map((yard) => ({
  value: yard.label,
  label: yard.label,
  children: yard.children.map((lane) => ({
    value: lane.label,
    label: lane.label,
    rawData: lane.value,
  })),
}));

const trainOptions = trains.map((train) => ({
  value: train.label,
  label: train.label,
  children: train.children.map((lane) => ({
    value: lane.label,
    label: lane.label,
    rawData: lane.value,
  })),
}));
const App = () => {
  const wsRef = useRef(null);
  const dispatch = useDispatch();
  const showBypass = useSelector((state) => state.status.showBypass);
  const blockObsId = useSelector((state) => state.status.blockObsId);
  const autoDrivingCars = useSelector((state) => state.status.autoDrivingCars);
  const vehicleStatus = useSelector((state) => state.status.vehicleStatus);
  const adVersion = useSelector((state) => state.status.adVersion);
  const [type, setType] = useState("DEFAULT");
  const [blacklistedLane, setBlacklistedLane] = useState("");
  const [trainOption, setTrainOptions] = useState(null);
  const [yardOption, setYardOptions] = useState(null);

  useEffect(() => {
    ws.connect((data) => {
      worker.postMessage({
        source: "realtime",
        data: data,
      });
    });
    wsRef.current = ws;

    return () => {
      ws.close();
    };
  }, []);

  useEffect(() => {
    worker.onmessage = (event) => {
      const data = event.data;
      switch (data.type) {
        case "SimWorldUpdate":
          if (data.blockObsId) {
            dispatch(setBlockObsId(data.blockObsId));
          }
          if (!!data.borrowRequest !== showBypass) {
            dispatch(toggleBypass(data.borrowRequest));
          }
          if (data.autoDrivingCar) {
            dispatch(setAutoDrivingCars(data.autoDrivingCar));
          }
          break;
        case "SystemInfo":
          dispatch(setVehicleStatus(data.data));
          break;
        case "ProjectVersionCheckResult":
          dispatch(setAdVersion(data.version));
          break;
        case "VehicleParam":
          // console.log(data, "VehicleParam");
          break;
        default:
          break;
      }
    };
  }, [dispatch, showBypass]);

  const handleBypassOk = () => {
    ws.requestBypassObstacle(blockObsId, true);
  };

  const handleBypassCancel = () => {
    ws.requestBypassObstacle(blockObsId, false);
  };

  const onSendYard = () => {
    if (!yardOption) {
      return message.error("Please select a yard");
    }
    const start = {
      x: autoDrivingCars.positionX,
      y: autoDrivingCars.positionY,
      z: 0,
    };
    const start_heading = autoDrivingCars.heading;
    ws.sendDemonstrateRequest(
      start,
      start_heading,
      yardOption,
      type,
      blacklistedLane
    );
  };

  const onSendTrain = () => {
    if (!trainOption) {
      return message.error("Please select a train");
    }
    const start = {
      x: autoDrivingCars.positionX,
      y: autoDrivingCars.positionY,
      z: 0,
    };
    const start_heading = autoDrivingCars.heading;
    ws.sendDemonstrateRequest(
      start,
      start_heading,
      trainOption,
      type,
      blacklistedLane
    );
  };

  const confirmArrive = (e) => {
    ws.requestImmediatelyArrived();
    message.success("Click on Yes");
  };
  const cancelArrive = (e) => {
    message.warning("Click on No");
  };

  const confirmCircle = (e) => {
    const start = {
      x: autoDrivingCars.positionX,
      y: autoDrivingCars.positionY,
      z: 0,
    };
    const start_heading = autoDrivingCars.heading;
    const end = {
      x: -2708.450657666,
      y: 2111.6562965,
      z: 10.924381586,
    };
    ws.requestRoute(start, start_heading, [], end, null, true);
    message.success("Click on Yes");
  };
  const cancelCircle = (e) => {
    message.warning("Click on No");
  };
  return (
    <div>
      <Modal
        title="ByPass"
        closable={{ "aria-label": "Custom Close Button" }}
        open={showBypass}
        onOk={handleBypassOk}
        onCancel={handleBypassCancel}
      >
        <p>Do you agree to bypass the obstacle?</p>
      </Modal>
      <Flex gap="middle" justify="center" wrap>
        <Card
          title="Vehicle Status"
          variant="borderless"
          style={{ width: "45%" }}
        >
          <Row gutter={[16, 16]} wrap>
            <Col span={12}>
              <Card variant="borderless">
                <Statistic
                  title="CPU"
                  value={vehicleStatus?.cpu * 100}
                  precision={2}
                  valueStyle={{ color: "#3f8600" }}
                  suffix="%"
                />
              </Card>
            </Col>
            <Col span={12}>
              <Card variant="borderless">
                <Statistic
                  title="Disk"
                  value={vehicleStatus?.disk * 100}
                  precision={2}
                  valueStyle={{ color: "#3f8600" }}
                  suffix="%"
                />
              </Card>
            </Col>
            <Col span={12}>
              <Card variant="borderless">
                <Statistic
                  title="Memory"
                  value={vehicleStatus?.memory * 100}
                  precision={2}
                  valueStyle={{ color: "#3f8600" }}
                  suffix="%"
                />
              </Card>
            </Col>
            <Col span={12}>
              <Card variant="borderless">
                <Statistic
                  title="AD Statu"
                  value={vehicleStatus?.status?.toUpperCase()}
                  valueStyle={{ color: "#3f8600" }}
                />
              </Card>
            </Col>
            <Col span={24}>
              <Card variant="borderless">
                <Statistic
                  title="AD Version"
                  value={adVersion?.toUpperCase()}
                  valueStyle={{ color: "#3f8600" }}
                />
              </Card>
            </Col>
          </Row>
        </Card>
        <Card
          title="Vehicle dispatching station"
          variant="borderless"
          style={{ width: "45%" }}
        >
          <Flex gap="middle" justify="center">
            <Popconfirm
              title="Immediately arrive at the station"
              description="Are you sure immediately arrive at the station?"
              onConfirm={confirmArrive}
              onCancel={cancelArrive}
              okText="Yes"
              cancelText="No"
            >
              <Button type="primary">Immediately arrive at the station</Button>
            </Popconfirm>
            <Popconfirm
              title="Start running circle test"
              description="Are you sure start running circle test?"
              onConfirm={confirmCircle}
              onCancel={cancelCircle}
              okText="Yes"
              cancelText="No"
            >
              <Button type="primary">Start running circle test</Button>
            </Popconfirm>
          </Flex>
          <Form
            labelCol={{ span: 4 }}
            wrapperCol={{ span: 20 }}
            layout="horizontal"
            size={"large"}
            style={{ maxWidth: 700, marginTop: 20 }}
          >
            <Form.Item label="Type">
              <Select
                options={typeOptions}
                defaultValue={type}
                onChange={(value) => {
                  setType(value);
                }}
              ></Select>
            </Form.Item>
            <Form.Item label="Blacklisted">
              <Input
                placeholder="Please enter IDs separated by commas"
                value={blacklistedLane}
                onChange={(e) => setBlacklistedLane(e.target.value)}
              />
            </Form.Item>
            <Form.Item label="Yard">
              <Cascader
                options={yardOptions}
                onChange={(value, selectedOptions) => {
                  if (value) {
                    setYardOptions(
                      selectedOptions[selectedOptions.length - 1].rawData
                    );
                  } else {
                    setYardOptions(null);
                  }
                }}
              />
            </Form.Item>
            <Form.Item label="Train">
              <Cascader
                options={trainOptions}
                onChange={(value, selectedOptions) => {
                  if (value) {
                    setTrainOptions(
                      selectedOptions[selectedOptions.length - 1].rawData
                    );
                  } else {
                    setTrainOptions(null);
                  }
                }}
              />
            </Form.Item>
            <Form.Item {...tailLayout}>
              <Space>
                <Button type="primary" htmlType="submit" onClick={onSendYard}>
                  Send Yard
                </Button>
                <Button type="primary" htmlType="button" onClick={onSendTrain}>
                  Send Train
                </Button>
              </Space>
            </Form.Item>
          </Form>
        </Card>
      </Flex>
    </div>
  );
};

export default App;
